const body = $input.first().json.body || $input.first().json;

const validStatuses = ['open','in_progress','fixed_pending_retest','partially_fixed','accepted_risk'];
if (!body.finding_id) return [{ json: { valid: false, error: 'finding_id required' } }];
if (body.status && !validStatuses.includes(body.status)) {
  return [{ json: { valid: false, error: `Invalid status. Must be one of: ${validStatuses.join(', ')}` } }];
}

return [{ json: {
  valid: true,
  finding_id: body.finding_id,
  status: body.status || 'in_progress',
  owner: body.owner || null,
  evidence_of_fix: body.evidence_of_fix || null,
  notes: body.notes || null,
  external_ticket_id: body.external_ticket_id || null
} }];

const body = $input.first().json.body || $input.first().json;
const updates = Array.isArray(body) ? body : body.updates || [];
return updates.map(u => ({ json: {
  finding_id: u.finding_id,
  status: u.status,
  owner: u.owner,
  notes: u.notes
} }));

